('00d620bd-b25f-484b-aa6c-14320374de71', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"AC26E28F348840C0CE322AD3996AECD9\",\"from\":\"43886412091411@lid\",\"type\":\"text\",\"content\":\"Halo\",\"timestamp\":1770626399}', 'DELIVERED', 1, 3, NULL, '2026-02-09 08:40:00.565', '2026-02-09 08:40:00.565', NULL, 200, '', NULL, 'msg_AC26E28F348840C0CE322AD3996AECD9', '2026-02-09 08:39:58.468', '2026-02-09 08:40:00.566'),
('02ab6575-3b19-4b7e-aec1-21bd7a11ce42', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"AC171ABFC7F08F0CC30C0206DB12A0A0\",\"from\":\"43886412091411@lid\",\"type\":\"text\",\"content\":\"Untuk price list terbaru kamu tahu?\",\"timestamp\":1770644293}', 'DELIVERED', 1, 3, NULL, '2026-02-09 13:38:15.088', '2026-02-09 13:38:15.088', NULL, 200, '{\"message\":\"Wah, kalau untuk daftar harga *terbaru* persisnya saya tidak punya informasi *real-time* nih, karena harga di setiap kafe itu bisa berubah sewaktu-waktu tergantung kebijakan mereka.\\n\\nTapi, sebagai **perkiraan**, rata-rata harga kopi di kafe-kafe di daerah Braga itu biasanya mulai dari Rp25.000 sampai Rp45.000an untuk minuman kopi basic seperti espresso, americano, atau latte. Kalau untuk makanan ringan atau camilan pendamping, harganya juga bervariasi.\\n\\nSaran saya, untuk info harga paling akurat, kamu bisa coba cek langsung di media sosial kafe yang kamu tuju atau via aplikasi pesan antar makanan sebelum datang, ya!\\n\\n**intent:** jam_buka_harga\\n**clarifying_question:** null\"}', NULL, 'msg_AC171ABFC7F08F0CC30C0206DB12A0A0', '2026-02-09 13:38:10.225', '2026-02-09 13:38:15.089'),
