('0f9949d7-91a2-45d0-ae53-f3add62bead6', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"AC9E14B8D98C04AEEFA70FB13F8EA96F\",\"from\":\"43886412091411@lid\",\"type\":\"text\",\"content\":\"Di daerah Braga ada tempat kopi?\",\"timestamp\":1770644238}', 'DELIVERED', 1, 3, NULL, '2026-02-09 13:37:20.156', '2026-02-09 13:37:20.156', NULL, 200, '{\"message\":\"Tentu saja! Daerah Braga itu surganya tempat kopi yang asyik-asyik, lho. Kamu bisa coba beberapa rekomendasi ini:\\n\\n*   **Kopi Toko Djawa:** Ini salah satu yang paling terkenal, tempatnya klasik dan kopinya enak. Selalu ramai, apalagi pas *weekend*.\\n*   **Braga Art Cafe:** Suasana kafe ini lebih santai dan artistik, cocok buat kamu yang mau ngopi sambil menikmati suasana Braga.\\n*   **Daily Routine Coffee:** Tempatnya lebih modern dan *cozy*, pas buat yang mau kerja atau sekadar ngobrol santai.\\n\\nSemoga membantu ya!\"}', NULL, 'msg_AC9E14B8D98C04AEEFA70FB13F8EA96F', '2026-02-09 13:37:15.912', '2026-02-09 13:37:20.157'),
