('5506eda8-0885-40b0-9aa1-751c7bfd4a2f', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"ACEE5F7D818EAAFD3D583C54C17EBFEF\",\"from\":\"120363420137806595@g.us\",\"type\":\"text\",\"content\":\"Gg\",\"timestamp\":1770628750}', 'DELIVERED', 1, 3, NULL, '2026-02-09 09:19:14.021', '2026-02-09 09:19:14.021', NULL, 200, '{\"message\":\"Gg! That stands for \\\"Good game.\\\"\\n\\nIt\'s a common phrase, especially in online gaming, to show sportsmanship at the end of a match, regardless of who won or lost.\\n\\nHope you had a good game yourself! Is there anything specific you wanted to chat about, or just sharing a friendly \'gg\'?\"}', NULL, 'msg_ACEE5F7D818EAAFD3D583C54C17EBFEF', '2026-02-09 09:19:08.749', '2026-02-09 09:19:14.022'),
