('63a1456f-456b-4b4f-80ce-c0515b5d3f19', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"3EB05469C60E07747641E0\",\"from\":\"120363420137806595@g.us\",\"type\":\"text\",\"content\":\"{   \\\"lastUserMessage\\\": \\\"{{$json.prompt}}\\\",   \\\"lastBotReply\\\": \\\"{{$json.response}}\\\" }006\",\"timestamp\":1770628950}', 'DELIVERED', 1, 3, NULL, '2026-02-09 09:22:32.783', '2026-02-09 09:22:32.783', NULL, 200, '{\"message\":\"```json\\n{\\n  \\\"lastUserMessage\\\": \\\"{{$json.prompt}}\\\",\\n  \\\"lastBotReply\\\": \\\"{{$json.response}}\\\"\\n}\\n```\"}', NULL, 'msg_3EB05469C60E07747641E0', '2026-02-09 09:22:29.545', '2026-02-09 09:22:32.785'),
