INSERT INTO `webhooks` (`id`, `organization_id`, `instance_id`, `event_type`, `payload`, `status`, `attempts`, `max_attempts`, `next_retry_at`, `last_attempt_at`, `delivered_at`, `failed_at`, `response_status`, `response_body`, `error_message`, `idempotency_key`, `created_at`, `updated_at`) VALUES
('683bacdd-9135-4e25-8b43-5b40d9280949', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'connection.connected', '{\"status\":\"CONNECTED\",\"phone_number\":\"628972285019:10\"}', 'DELIVERED', 1, 3, NULL, '2026-02-09 08:45:25.084', '2026-02-09 08:45:25.084', NULL, 200, '', NULL, 'conn_0190b6fe-dae2-4875-9b48-ff074e336b5c_1770626724153', '2026-02-09 08:45:24.157', '2026-02-09 08:45:25.085'),
('690b1c65-aaff-44bf-9555-4af9f6858c9f', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"AC0A536E51021D2AAA2BDD5A3206A076\",\"from\":\"43886412091411@lid\",\"type\":\"text\",\"content\":\"Bisa berita tahu saya apa itu ai\",\"timestamp\":1770630183}', 'DELIVERED', 1, 3, NULL, '2026-02-09 09:43:06.771', '2026-02-09 09:43:06.771', NULL, 200, '{\"message\":\"Tentu saja! Dengan senang hati saya jelaskan.\\n\\nSecara sederhana, **AI (Artificial Intelligence)** atau dalam Bahasa Indonesia disebut **Kecerdasan Buatan**, adalah bidang ilmu komputer yang berfokus pada pengembangan sistem atau mesin yang mampu melakukan tugas-tugas yang biasanya membutuhkan kecerdasan manusia.\\n\\nBayangkan seperti ini: kita mencoba mengajarkan komputer untuk berpikir, belajar, dan mengambil keputusan seperti manusia.\\n\\nBeberapa poin penting tentang apa itu AI:\\n\\n1.  **Meniru Kecerdasan Manusia:** Tujuan utamanya adalah membuat mesin bisa meniru atau mensimulasikan kemampuan kognitif manusia, seperti belajar dari pengalaman, memecahkan masalah, mengenali pola, memahami bahasa, bahkan membuat keputusan.\\n2.  **Bukan Sekadar Otomatisasi:** AI berbeda dengan program komputer biasa yang hanya mengikuti instruksi yang sudah ditetapkan. AI dirancang untuk bisa *belajar* dan *beradaptasi* tanpa perlu diprogram ulang setiap saat untuk setiap skenario baru.\\n3.  **Berbasis Data dan Algoritma:** AI \\\"belajar\\\" dengan menganalisis sejumlah besar data. Dari data tersebut, algoritma AI akan menemukan pola dan hubungan, kemudian menggunakan pola tersebut untuk membuat prediksi atau mengambil tindakan.\\n4.  **Cabang-cabang dalam AI:** Dunia AI itu luas sekali. Ada Machine Learning (ML), Deep Learning (DL), Natural Language Processing (NLP), Computer Vision, Robotika, dan masih banyak lagi. Masing-masing fokus pada aspek kecerdasan yang berbeda.\\n5.  **Tujuan:** Untuk mengotomatisasi tugas, meningkatkan efisiensi, memecahkan masalah yang terlalu kompleks bagi manusia, dan menciptakan inovasi yang sebelumnya tidak terbayangkan.\\n\\nSingkatnya, AI adalah upaya kita untuk menciptakan *kecerdasan di dalam mesin* agar mereka bisa membantu kita dengan cara-cara yang lebih cerdas dan adaptif.\\n\\nApakah penjelasan ini membantu, atau ada bagian yang ingin Anda gali lebih dalam lagi?\"}', NULL, 'msg_AC0A536E51021D2AAA2BDD5A3206A076', '2026-02-09 09:43:02.216', '2026-02-09 09:43:06.773'),
('6a5e7e8c-78ac-48df-b88c-7c3f620c11a6', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"AC34FD0E315EF61BFB19D1C26A203162\",\"from\":\"43886412091411@lid\",\"type\":\"text\",\"content\":\"Kalau wisata malam hari ada makanan apa ya di bandunh\",\"timestamp\":1770646564}', 'DELIVERED', 2, 3, '2026-02-09 14:16:22.094', '2026-02-09 14:16:46.304', '2026-02-09 14:16:46.304', NULL, 200, '{\"message\":\"Wah, tentu saja! Bandung itu surganya kuliner malam hari. Banyak banget pilihan makanan enak yang bikin betah nongkrong sampai larut. Ini beberapa rekomendasi yang sering dicari:\\n\\n1.  **Nasi Kalong**: Ini nasi hitam yang dimasak dengan kluwek, rasanya gurih manis. Biasanya disajikan dengan aneka lauk prasmanan rumahan yang rasanya juara banget, seperti ayam goreng, jengkol balado, atau tahu tempe. Cocok buat yang cari makan berat dan nendang di malam hari.\\n2.  **Sate**: Sate ayam atau sate kambing di Bandung juga banyak yang buka sampai malam. Salah satu yang legendaris itu Sate Hadori atau Sate Ma\'mun. Dagingnya empuk, bumbunya meresap, dan nikmat banget disantap hangat-hangat.\\n3.  **Surabi**: Kalau mau yang ringan tapi khas Bandung, coba deh surabi! Ada surabi original dengan kinca manis atau surabi oncom yang pedas gurih. Banyak tempat surabi yang buka sampai tengah malam, misalnya di Jalan Setiabudi atau Cihampelas.\\n4.  **Mie Kocok**: Kuah kaldu sapi yang gurih kental dengan mie kuning, kikil, tauge, dan taburan seledri bawang goreng. Hangat-hangatnya pas banget buat suasana malam Bandung yang sejuk.\\n5.  **Cuanki**: Mirip bakso, tapi dengan tambahan tahu, pangsit, dan siomay kering. Kuahnya segar dan ringan. Ada beberapa tempat cuanki yang terkenal dan buka sampai malam.\\n\\nItu baru beberapa lho, masih banyak lagi jajanan malam lainnya seperti bajigur/bandrek untuk menghangatkan badan, atau aneka *street food* di beberapa titik keramaian.\\n\\n**intent:** kuliner\\n**clarifying_question:** Kamu