('cbcb2e09-be4a-4c84-a312-38bd14b22c03', 'fa275f1a-f014-479e-9111-97c2f8a67315', '0190b6fe-dae2-4875-9b48-ff074e336b5c', 'message.received', '{\"id\":\"3EB04306859FB1BC49878D\",\"from\":\"120363420137806595@g.us\",\"type\":\"document\",\"content\":\"My workflow (7).json\",\"timestamp\":1770629093}', 'DELIVERED', 1, 3, NULL, '2026-02-09 09:25:04.458', '2026-02-09 09:25:04.458', NULL, 200, '{\"message\":\"Okay, I can create a sample JSON structure for a workflow. Since you didn\'t provide specific details, I\'ll create a generic content publication workflow. The \\\"(7)\\\" could refer to an ID or version, so I\'ll incorporate it as a unique `workflowId`.\\n\\n```json\\n{\\n  \\\"workflowId\\\": \\\"WF-CP-007\\\",\\n  \\\"workflowName\\\": \\\"Content Publication Workflow\\\",\\n  \\\"version\\\": \\\"1.0.0\\\",\\n  \\\"description\\\": \\\"A standardized process for creating, reviewing, and publishing marketing content (e.g., blog posts, articles).\\\",\\n  \\\"status\\\": \\\"Active\\\",\\n  \\\"createdAt\\\": \\\"2023-10-27T10:00:00Z\\\",\\n  \\\"createdBy\\\": \\\"AI Assistant\\\",\\n  \\\"lastModifiedAt\\\": \\\"2023-10-27T10:00:00Z\\\",\\n  \\\"trigger\\\": {\\n    \\\"type\\\": \\\"Manual\\\",\\n    \\\"details\\\": \\\"Initiated by a content creator or project manager.\\\"\\n  },\\n  \\\"steps\\\": [\\n    {\\n      \\\"stepId\\\": \\\"S1\\\",\\n      \\\"name\\\": \\\"Draft Content\\\",\\n      \\\"type\\\": \\\"Task\\\",\\n      \\\"description\\\": \\\"Content creator drafts the initial article/post.\\\",\\n      \\\"assigneeRole\\\": \\\"Content Creator\\\",\\n      \\\"inputs\\\": [\\\"Topic Brief\\\", \\\"Keywords\\\", \\\"Outline (Optional)\\\"],\\n      \\\"outputs\\\": [\\\"Draft Content Document (e.g., Google Doc, Word File)\\\"],\\n      \\\"dependencies\\\": [],\\n      \\\"status\\\": \\\"Pending\\\"\\n    },\\n    {\\n      \\\"stepId\\\": \\\"S2\\\",\\n      \\\"name\\\": \\\"Editor Review\\\",\\n      \\\"type\\\": \\\"Approval\\\",\\n      \\\"description\\\": \\\"Editor reviews content for grammar, style, accuracy, and brand voice.\\\",\\n      \\\"assigneeRole\\\": \\\"Editor\\\",\\n      \\\"inputs\\\": [\\\"Draft Content Document\\\"],\\n      \\\"outputs\\\": [\\\"Reviewed Content Document\\\", \\\"Feedback Notes\\\"],\\n      \\\"dependencies\\\": [\\\"S1\\\"],\\n      \\\"conditions\\\": {\\n        \\\"onApproval\\\": \\\"Proceed to S3\\\",\\n        \\\"onRejection\\\": \\\"Return to S1 (with feedback)\\\"\\n      },\\n      \\\"status\\\": \\\"Pending\\\"\\n    },\\n    {\\n      \\\"stepId\\\": \\\"S3\\\",\\n      \\\"name\\\": \\\"SEO Optimization\\\",\\n      \\\"type\\\": \\\"Task\\\",\\n      \\\"description\\\": \\\"SEO specialist optimizes content for search engines (keywords, meta descriptions, internal links).\\\",\\n      \\\"assigneeRole\\\": \\\"SEO Specialist\\\",\\n      \\\"inputs\\\": [\\\"Reviewed Content Document\\\", \\\"Target Keywords\\\"],\\n      \\\"outputs\\\": [\\\"Optimized Content Document\\\"],\\n      \\\"dependencies\\\": [\\\"S2\\\"],\\n      \\\"status\\\": \\\"Pending\\\"\\n    },\\n    {\\n      \\\"stepId\\\": \\\"S4\\\",\\n      \\\"name\\\": \\\"Marketing Review & Approval\\\",\\n      \\\"type\\\": \\\"Approval\\\",\\n      \\\"description\\\": \\\"Marketing Lead gives final approval and schedules publication.\\\",\\n      \\\"assigneeRole\\\": \\\"Marketing Lead\\\",\\n      \\\"inputs\\\": [\\\"Optimized Content Document\\\"],\\n      \\\"outputs\\\": [\\\"Approved Content Document\\\", \\\"Publication Schedule\\\"],\\n      \\\"dependencies\\\": [\\\"S3\\\"],\\n      \\\"conditions\\\": {\\n        \\\"onApproval\\\": \\\"Proceed to S5\\\",\\n        \\\"onRejection\\\": \\\"Return to S2 or S3 (with specific feedback)\\\"\\n      },\\n      \\\"status\\\": \\\"Pending\\\"\\n    },\\n    {\\n      \\\"stepId\\\": \\\"S5\\\",\\n      \\\"name\\\": \\\"Publish Content\\\",\\n      \\\"type\\\": \\\"Automated/Manual Task\\\",\\n      \\\"description\\\": \\\"Content is published to the designated platform (e.g., CMS, blog).\\\",\\n      \\\"assigneeRole\\\": \\\"System/Publisher\\\",\\n      \\\"inputs\\\": [\\\"Approved Content Document\\\", \\\"Publication Schedule\\\"],\\n      \\\"outputs\\\": [\\\"Published URL\\\"],\\n      \\\"dependencies\\\": [\\\"S4\\\"],\\n      \\\"status\\\": \\\"Pending\\\"\\n    },\\n    {\\n      \\\"stepId\\\": \\\"S6\\\",\\n      \\\"name\\\": \\\"Promote Content\\\",\\n      \\\"type\\\": \\\"Task\\\",\\n      \\\"description\\\": \\\"Share published content on social media, newsletters, etc.\\\",\\n      \\\"assigneeRole\\\": \\\"Marketing Team\\\",\\n      \\\"inputs\\\": [\\\"Published URL\\\"],\\n      \\\"outputs\\\": [\\\"Promotional Posts/Campaigns\\\"],\\n      \\\"dependencies\\\": [\\\"S5\\\"],\\n      \\\"status\\\": \\\"Pending\\\"\\n    }\\n  ],\\n  \\\"conclusion\\\": {\\n    \\\"type\\\": \\\"Manual/Automated\\\",\\n    \\\"details\\\": \\\"Workflow successfully completed upon content promotion and tracking.\\\"\\n  }\\n}\\n```\"}', NULL, 'msg_3EB04306859FB1BC49878D', '2026-02-09 09:24:52.538', '2026-02-09 09:25:04.460'),
