('503f2c8a-f826-44ff-8a8b-7061576376d3', 'fa275f1a-f014-479e-9111-97c2f8a67315', '4e9f63f0-ce29-4b11-8e99-51bf3cd89225', 1, NULL, '{\"id\":\"A5284D3B6F8579E62C34FE1D46319979\",\"from\":\"120363187254621709@g.us\",\"type\":\"text\",\"content\":\"Jumlah tamu : 40 orang\\n\\n *Sarapan Pagi jam 8:00 Makanan utama* \\n\\n•Nasi putih\\n•Tahu bacem dan tempe bacem\\n•Tempe orek kering\\n• Ayam Serundeng\\n• sambal biasa\\n•selada bokor\\n•labu rebus dan wortel rebus\\n• Buah potong (semangka dan Melon) \\n• Teh Hangat\\n• Air botol mineral\\n\\n\\n *Cofee Break jam 9:30* \\n•  cup cofee\\n• Teh hangat\\n• kopi creamy Latte\\n• kopi kapal api (kopi saja) \\n• gula putih\\n\\n\\n *Makan Siang jam 11:45* \\n• Sop Iga\\n• Bebek goreng\\n• mustofa/kentang balado\\n• Karedok\\n•kerupuk udang\\n• sambal ijo (untuk sop) \\n• sambal biasa\\n• lalapan selada bokor dan timun\\n•Buah potong semangka dan melon\\n• air mineral botol\\n• Teh hangat\\n\\n *Kue Basah* \\n• putu ayu\\n• kue lapis\\n• kue soes\\n• risol\\n• Pastel\\n• Puding\\n• jeruk sunkis\",\"timestamp\":1770611412}', 200, NULL, '{\"message\":\"Workflow was started\"}', 1178, NULL, '2026-02-09 08:17:50.682'),
